import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../etc/passwd";
        String directoryPath = "/path/to/safe/directory/";

        // Validate user input to prevent path traversal
        if (!userInput.contains("..") && !userInput.startsWith("/")) {
            String fullPath = directoryPath + userInput;

            try {
                File file = new File(fullPath);
                if (file.exists() && file.isFile()) {
                    byte[] fileContent = Files.readAllBytes(file.toPath());
                    System.out.println(new String(fileContent));
                } else {
                    System.out.println("File not found.");
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("Invalid input. Path traversal detected.");
        }
    }
}

